"use strict";(()=>{const W=window.WTSRegistry,R=window.WTSRecords,{$,$$,state,toast,auth,view,signOut}=W;$$('.nav').forEach(b=>b.onclick=()=>view(b.dataset.view));$$('[data-open]').forEach(b=>b.onclick=()=>view(b.dataset.open));$$('[data-action="addStudent"]').forEach(b=>b.onclick=()=>R.studentForm());$$('[data-action="addStaff"]').forEach(b=>b.onclick=()=>R.staffForm());$("#studentFind").onclick=R.loadStudents;$("#staffFind").onclick=R.loadStaff;$("#accessFind").onclick=window.WTSAccess.load;$("#studentClass").onchange=R.loadStudents;$("#studentStatus").onchange=R.loadStudents;$("#staffStatus").onchange=R.loadStaff;$("#refresh").onclick=()=>R.loadContext().then(()=>state.views[state.currentView]?.()).catch(e=>{toast(e.message,"error");if(/AUTH|PERMISSION|login/i.test(e.message))signOut()});$("#login").onclick=signOut;$("#gateForm").onsubmit=e=>{e.preventDefault();$("#authError").textContent="Connecting…";sessionStorage.setItem(W.STORE,JSON.stringify({code:$("#adminCode").value.trim(),secret:$("#adminSecret").value}));R.loadContext().then(()=>{$("#authError").textContent="";toast("Central Registry opened.","success")}).catch(err=>{sessionStorage.removeItem(W.STORE);W.connected(false,err.message);$("#adminSecret").value=""})};$("#recordForm").onsubmit=async e=>{e.preventDefault();if(!state.handler)return;$("#saveRecord").disabled=true;try{await state.handler(e.currentTarget);$("#formDialog").close()}catch(err){toast(err.message,"error")}finally{$("#saveRecord").disabled=false}};W.connected(false);try{const a=auth();$("#adminCode").value=a.code;R.loadContext().catch(()=>signOut())}catch{$("#adminCode").focus()}})();